#!/usr/bin/env node
/**
 * Scenario runner TEMPLATE — copy this to `sdk/org/scenarios/<id>/run.mjs` and fill in the Acts.
 * It bakes in every hardening pattern the campaigns learned the hard way (see the harness API +
 * hardening patterns in automation/instances/scenario-campaign/prompt.common.md): per-Act
 * checkpointing + resume, a keepalive pinger, a resilient `send`
 * that survives a full pod restart, a scripted ask answerer, attachment + live-app + inbound helpers,
 * and trace-based assertions.
 *
 * NOTE: `ThingSession` now self-heals SESSION EVICTION natively (a long turn's sub-sessions can push
 * a small pod past MAX_SESSIONS): pullEvents treats a post-work 404 as turn-complete, and it
 * re-establishes an evicted session before the next send. The `thing.send` wrapper below is the extra
 * belt for a FULL pod roll/restart. For a session-heavy scenario, also raise the cap on the test pod:
 *   ssh … 'kubectl set env deployment/lmthing MAX_SESSIONS=25 -n user-<id>'
 *
 *   cd sdk/org/scenarios/harness && node ../<id>/run.mjs [--acts=1,2,3] [--fresh]
 *
 * Replace every `SCENARIO_*` below, then write your Acts where marked.
 */
import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'node:fs';
import { createHmac } from 'node:crypto';
import { getUser } from '../harness/provision.mjs';
import { Pod } from '../harness/lib/pod.mjs';
import { ThingSession } from '../harness/lib/thing.mjs';
import { Report } from '../harness/lib/report.mjs';
import { mergePodEnv, waitPodReady, waitPodSettled } from '../harness/lib/gateway.mjs';
import { SDK_ORG } from '../harness/lib/paths.mjs';

// ── config — EDIT THESE ─────────────────────────────────────────────────────────
const ID = 'SCENARIO_ID'; // e.g. '06-something'
const TITLE = 'SCENARIO_TITLE';
const LABEL = 'SCENARIO_LABEL'; // provision.mjs label (disposable user prefix)
const PROJECT = 'SCENARIO_PROJECT'; // the project id the scenario runs in ('user' = default)
/** Any integration/env secrets the scenario needs, loaded BEFORE the first session. */
const POD_ENV = {
  // INTEGRATION_DEMO_BASE_URL: 'https://httpbin.org/anything',
  // INTEGRATION_DEMO_API_TOKEN: 'demo-token',
  // INTEGRATION_DEMO_WEBHOOK_SECRET: 'demo-hmac-secret',
};

const RESULTS = `${SDK_ORG}/scenarios/${ID}/results`;
const CHECKPOINT = `${RESULTS}/checkpoint.json`;
const argActs = (process.argv.find((a) => a.startsWith('--acts=')) ?? '').slice(7);
const ACTS = argActs ? argActs.split(',').map(Number) : [1, 2, 3, 4];
const FRESH = process.argv.includes('--fresh');
const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const now = () => Date.now();

// ── checkpoint (resume from the last good Act) ──────────────────────────────────
function loadCheckpoint() {
  if (FRESH || !existsSync(CHECKPOINT)) return { acts: {}, sessionId: null };
  try { return JSON.parse(readFileSync(CHECKPOINT, 'utf8')); } catch { return { acts: {}, sessionId: null }; }
}
function saveCheckpoint(cp) {
  mkdirSync(RESULTS, { recursive: true });
  writeFileSync(CHECKPOINT, JSON.stringify(cp, null, 2));
  console.log(`\n💾 checkpoint → ${CHECKPOINT}`);
}

// ── scripted asks: approve/deny consent, settle any other ask so a run never hangs ──
===HARNESS README===
# Live prod scenarios

Two high-complexity, end-to-end scenarios that exercise the **system spaces** (`system-appbuilder`,
`system-architect`, `system-research`, `system-store`, `system-engineer`) and the **unified event
pipeline** through the **THING agent**, against the **live production cluster and a live LLM**.

Every scenario runs as a real user would: a disposable prod test user, a real compute pod, a real
THING chat session, real model calls. Nothing is mocked. If a scenario passes, the feature works in
production — not in a unit test.

| # | Scenario | Covers |
|---|---|---|
| [05](./05-latam/scenario.md) | **Latin America** — six months, nine countries, one growing project | the full lifecycle: incremental space growth, integrations, a THING-controlled **project app** automating bookings/transport/notifications, live in the project web app |
| [06](./06-tanzania/scenario.md) | **Tanzania trip** — one attachment becomes spaces + a live, updatable app | file ingest (`system-files`); per-leg spaces; live-project app (`writeProjectTable`/`Page`/`Api` + rows seed); `db:write` later-update; compound + multilingual ask |

## Running one

```bash
cd sdk/org/scenarios/harness
node smoke.mjs                 # prove the harness + prod are healthy first (≈1 min)
node ../05-latam/run.mjs        # a scenario's runner writes its own report
```

Each scenario directory holds a `scenario.md` (the spec) and a `run.mjs` (the executable spec), and
writes `sdk/org/scenarios/<id>/results/report.md` plus a raw trace JSON. The **Actual results**
section of `scenario.md` is pasted back from that report, so the document is both the plan and the
record.

## Authoring a new scenario — the format + the workflow

The full **format** (the six-section `scenario.md` structure, the feature catalog, the validation
process, the harness API) and the **workflow** (run → triage → fix-in-product-with-a-test →
verify-live → report, plus the image-rebuild loop and multi-hour babysitting discipline) now live,
self-contained, in the automation instance that drives this campaign:
[`automation/instances/scenario-campaign/prompt.common.md`](../../../automation/instances/scenario-campaign/prompt.common.md)
(run it with `node automation/lmauto.mjs run scenario-campaign`).

To author one by hand, copy the template:

- **[`_template/`](./_template/)** — `cp -r _template <NN-slug>`, then fill **`<NN-slug>/scenario.md`**
