content.content:
1	/**
2	 * THING session driver — talks to a real agent session over the pod's HTTP API and gives a
3	 * scenario everything it needs to ASSERT on behaviour, not just on final text.
4	 *
5	 * Why HTTP and not the WebSocket the /chat SPA uses: the WS needs a dep and buys us nothing here.
6	 * The pod exposes the same surface over HTTP (sdk/org/libs/cli/src/server/web/agent-api.ts):
7	 *
8	 *   POST /api/sessions                      {projectId, agentSlug?, resumeSessionId?, budget?}
9	 *   POST /api/sessions/:id/message          {content}                         → 202
10	 *   GET  /api/sessions/:id/events?since=N&format=json                          → {events,lastSeq}
11	 *   GET  /api/sessions/:id/asks?format=json                                    → {asks}
12	 *   POST /api/sessions/:id/ask/:askId       {value}                            → answer a prompt
13	 *
14	 * The event stream is the full execution trace (sdk/org/libs/core/src/sandbox/trace.ts), so a
15	 * scenario can assert on the things that actually matter — which agents THING delegated to, which
16	 * consent-marked globals it called, which yields resolved, tokens burned, errors raised — instead
17	 * of grading a paragraph of prose.
18	 *
19	 * IMPORTANT (consent): the consent prompter is only wired for INTERACTIVE sessions
20	 * (session-manager.ts — `consentPrompter: args.interactive ? … : undefined`). A session created
21	 * through `POST /api/sessions` is interactive, so consent cards appear as asks here. Headless
22	 * paths (hooks, delegates, webhook dispatch) fail closed by design — that is a feature to assert,
23	 * not a bug to work around.
24	 */
25	
26	const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
27	
28	export class ThingSession {
29	  /**
30	   * @param {import('./pod.mjs').Pod} pod
31	   * @param {object} opts
32	   * @param {string} [opts.projectId='user']   project to run in ('user' = the default project)
33	   * @param {string} [opts.agentSlug='thing']  THING is the default agent
34	   * @param {string} [opts.spaceRef]           bind to a project SPACE's agent (`<space>/<agent>`)
35	   *        instead of THING — the only way to exercise that specialist's OWN capability profile.
36	   * @param {(descriptor:object)=>unknown} [opts.onAsk]  answer asks (consent cards, forms).
37	   *        Return `undefined` to leave the ask open (the scenario answers it manually).
38	   * @param {boolean} [opts.verbose=false]     stream a live log to stdout
39	   */
40	  constructor(pod, opts = {}) {
41	    this.pod = pod;
42	    this.projectId = opts.projectId ?? 'user';
43	    this.agentSlug = opts.agentSlug ?? 'thing';
44	    this.spaceRef = opts.spaceRef;
45	    this.onAsk = opts.onAsk;
46	    this.verbose = opts.verbose ?? false;
47	    this.sessionId = null;
48	    /** every trace event seen, in order — the scenario's source of truth */
49	    this.events = [];
50	    /** asks the driver saw, with what it answered */
51	    this.asks = [];
52	    this.lastSeq = 0;
53	  }
54	
55	  log(...a) {
56	    if (this.verbose) console.log('[thing]', ...a);
57	  }
58	
59	  /** Create the session. Init is async pod-side — `send()` waits it out. */
60	  async start({ resumeSessionId, budget, spaceRef = this.spaceRef } = {}) {
61	    const body = {
62	      projectId: this.projectId,
63	      agentSlug: this.agentSlug,
64	      // Bind the session to a PROJECT SPACE's own agent (`<space>/<agent>`) instead of THING
65	      // (session-manager `_initProjectSession` → `parseSpaceRef`). This is what lets a scenario
66	      // probe one specialist's real capability profile directly, rather than inferring it from
67	      // what THING chose to delegate.
68	      ...(spaceRef ? { spaceRef } : {}),
69	      ...(resumeSessionId ? { resumeSessionId } : {}),
70	      ...(budget ? { budget } : {}),
71	    };
72	    const { sessionId } = await this.pod.req('POST', '/api/sessions', body);
73	    this.sessionId = sessionId;
74	    this.log('session', sessionId);
75	    return sessionId;
76	  }
77	
78	  /** Resume an existing session id (post-restart auto-resume scenario). */
79	  async resume(sessionId) {
80	    return this.start({ resumeSessionId: sessionId });
81	  }
82	
83	  /**
84	   * Fast-forward past a RESUMED session's existing trace without attributing it to the next turn.
85	   *
86	   * A scenario that runs Act-by-Act (`--acts=`) resumes the same session from a FRESH process, where
87	   * `lastSeq` starts at 0 — so the first `pullEvents()` replays the WHOLE session history and
88	   * `turn(startSeq)` folds it into the first turn's slice. Any assertion over that slice then reads
89	   * *earlier Acts'* displays: scenario 10 saw a restraint check "pass" on a build summary printed
90	   * two Acts ago. Call this right after `start()`/`resume()` so a turn's events are only its own.
91	   */
92	  async syncToTail() {
93	    for (let i = 0; i < 30; i++) {
94	      const before = this.lastSeq;
95	      await this.pullEvents();
96	      if (this.lastSeq === before) break;
97	      await sleep(200);
98	    }
99	    this.events.length = 0; // replayed history is not the next turn's work
100	    return this.lastSeq;
101	  }
102	
103	  /**
104	   * Pull new trace events since `lastSeq`.
105	   *
106	   * A long turn can spawn many delegate/headless sub-sessions; on a small pod (`maxSessions`) the
107	   * session manager may EVICT this top-level session shortly after its turn completes, so a poll
108	   * then 404s ("unknown session"). That is not a turn failure — the work already landed (assert it
109	   * on real pod state). So a 404 is surfaced as a soft signal (`this.sessionGone = true`) rather
110	   * than thrown; the settle loop treats it as turn-end once work has been seen.
111	   */
112	  async pullEvents() {
113	    let res;
114	    try {
115	      res = await this.pod.req('GET', `/api/sessions/${this.sessionId}/events?since=${this.lastSeq}&format=json`);
116	    } catch (err) {
117	      if (err?.status === 404) {
118	        this.sessionGone = true;
119	        return [];
120	      }
121	      throw err;
122	    }
123	    const { events, lastSeq } = res;
124	    for (const e of events ?? []) {
125	      this.events.push(e.event);
126	      if (this.verbose) this.#logEvent(e.event);
127	    }
128	    if (typeof lastSeq === 'number') this.lastSeq = lastSeq;
129	    return events ?? [];
130	  }
131	
132	  #logEvent(ev) {
133	    switch (ev.type) {
134	      case 'yield':
135	        this.log(`  yield ${ev.kind}`, JSON.stringify(ev.args)?.slice(0, 140));
136	        break;
137	      case 'display':
138	        this.log('  display', JSON.stringify(ev.descriptor)?.slice(0, 200));
139	        break;
140	      case 'node_start':
141	        this.log(`  node_start ${ev.kind} ${ev.label}`);
142	        break;
143	      case 'node_end':
144	        this.log(`  node_end ${ev.nodeId} ${ev.status} ${ev.durationMs}ms`);
145	        break;
146	      case 'eval_error':
147	      case 'typecheck_error':
148	        this.log(`  !! ${ev.type}: ${ev.message?.slice(0, 200)}`);
149	        break;
150	      default:
151	        break;
152	    }
153	  }
154	
155	  /** Open asks, with the raw descriptor (a ConsentCard is `descriptor.type === 'ConsentCard'`). */
156	  async openAsks() {
157	    const { asks } = await this.pod.req('GET', `/api/sessions/${this.sessionId}/asks?format=json`);
158	    return asks ?? [];
159	  }
160	
161	  /**
162	   * Answer an ask. Consent approval is anything in {true, 'approve', {approved:true},
163	   * {approve:true}} (core/src/globals/consent.ts `isConsentApproval`); ANYTHING else — including
164	   * null — is a denial.
165	   */
166	  async answerAsk(askId, value) {
167	    await this.pod.req('POST', `/api/sessions/${this.sessionId}/ask/${askId}`, { value });
168	    this.log('answered ask', askId, JSON.stringify(value));
169	  }
170	
171	  /**
172	   * Send a user message and wait for the turn to settle.
173	   *
174	   * "Settled" = the session is idle AND the trace has stopped growing for `quietMs`. We can't
175	   * key on a single `turn_end` because delegates/forks emit their own in sub-contexts; the
176	   * idle+quiet pair is the only reliable edge over HTTP.
177	   *
178	   * While waiting we drain asks through `onAsk` — that is how consent cards get approved mid-turn.
179	   * A turn blocked on an unanswered ask never goes idle, so an un-handled consent card surfaces as
180	   * a timeout with the ask still open (which the scenario can assert on).
181	   */
182	  /**
183	   * Ensure `this.sessionId` still exists; if it was evicted (`maxSessions` on a small pod), start a
184	   * fresh session — resuming the old id when the pod still has its snapshot, else a clean new one.
185	   * The project (its spaces, app, db) persists on disk regardless, so a re-established session still
186	   * sees everything built so far; only in-VM conversation memory is lost (acceptable — the scenario
187	   * drives self-contained follow-ups).
188	   */
189	  async #ensureAlive() {
190	    if (!this.sessionId) return;
191	    const list = await this.pod.req('GET', '/api/sessions').catch(() => ({ sessions: [] }));
192	    const alive = (list.sessions ?? []).some((s) => s.sessionId === this.sessionId);
193	    if (alive) return;
194	    this.log('session evicted — re-establishing');
195	    const prev = this.sessionId;
196	    try {
197	      await this.start({ resumeSessionId: prev });
198	    } catch {
199	      await this.start();
200	    }
201	    this.lastSeq = 0;
202	    this.sessionGone = false;
203	  }
204	
205	  async send(content, opts = {}) {
206	    await this.#ensureAlive();
207	    return this.#dispatchAndWait(
208	      () => this.pod.req('POST', `/api/sessions/${this.sessionId}/message`, { content }),
209	      content,
210	      opts,
211	    );
212	  }
213	
214	  /**
215	   * Send a user message WITH attachments (the file-upload path the real UI uses).
216	   *
217	   * The HTTP `POST /message` route is content-only — it silently drops attachments
218	   * (`sessions.ts` wires `sendMessage: (content) => manager.sendMessage(id, content)`, no third
219	   * arg). Only the WebSocket path carries `attachmentIds` (`ws/agent.ts` →
220	   * `msg.attachments.map(a => a.id)`). So to attach a file we open the same `/api/ws` socket the
221	   * `/chat` SPA uses, send one `{type:'sendMessage', content, attachments}` frame, then fall back to
222	   * the normal HTTP trace-poll to await the turn (the socket also streams the trace, but reusing the
223	   * HTTP settle-loop keeps one code path for "turn finished").
224	   *
225	   * @param {string} content
226	   * @param {Array<{id:string,kind:string,mediaType:string,url?:string,filename?:string}>} attachments
227	   *        AttachmentRefs from `pod.upload()`. The server trusts only `id` (re-reads bytes by id).
228	   */
229	  async sendWithAttachments(content, attachments, opts = {}) {
230	    const refs = attachments.map((a) => ({
231	      id: a.id,
232	      kind: a.kind,
233	      mediaType: a.mediaType,
234	      url: a.url ?? `/api/uploads/${a.id}`,
235	      ...(a.filename ? { filename: a.filename } : {}),
236	    }));
237	    await this.#ensureAlive();
238	    return this.#dispatchAndWait(
239	      () => this.#wsSend({ type: 'sendMessage', content, attachments: refs }),
240	      `${content}  [+${refs.length} attachment(s)]`,
241	      opts,
242	    );
243	  }
244	
245	  /** Open the pod's chat WebSocket, send one frame, resolve when it's flushed, then close. */
246	  #wsSend(frame) {
247	    const wsBase = this.pod.base.replace(/^http/, 'ws');
248	    const tokenQ = this.pod.token ? `&access_token=${encodeURIComponent(this.pod.token)}` : '';
249	    const url = `${wsBase}/api/ws?sessionId=${this.sessionId}${tokenQ}`;
250	    return new Promise((resolve, reject) => {
251	      const ws = new WebSocket(url); // Node ≥22 global WebSocket — zero-dep
252	      const fail = (e) => reject(e instanceof Error ? e : new Error(`ws error: ${JSON.stringify(e)}`));
253	      ws.addEventListener('open', () => {
254	        ws.send(JSON.stringify(frame));
255	        // Give the frame a beat to flush, then close; the turn is awaited over HTTP.
256	        setTimeout(() => {
257	          try {
258	            ws.close();
259	          } catch {
260	            /* ignore */
261	          }
262	          resolve();
263	        }, 750);
264	      });
265	      ws.addEventListener('error', fail);
266	    });
267	  }
268	
269	  async #dispatchAndWait(dispatch, logLine, { timeoutMs = 600_000, quietMs = 4_000, pollMs = 1_500 } = {}) {
270	    const startSeq = this.events.length;
271	    const t0 = Date.now();
272	    await dispatch();
273	    this.log('→', logLine.slice(0, 140));
274	
275	    let lastChange = Date.now();
276	    let sawWork = false;
277	    let quietSince = null;
278	    this.sessionGone = false;
279	
280	    while (Date.now() - t0 < timeoutMs) {
281	      const fresh = await this.pullEvents();
282	      if (fresh.length) {
283	        lastChange = Date.now();
284	        sawWork = true;
285	        quietSince = null;
286	      }
287	
288	      // The session vanished mid-turn (evicted past `maxSessions`, or the pod rolled/woke from
289	      // scale-to-zero under us — sessions are in-memory). We saw work, but we do NOT know the turn
290	      // FINISHED: a long build (build_specialist → deep_research → architect) can be cut off with
291	      // nothing durable written. Returning silently here reports a killed turn as a completed one —
292	      // that is how scenario 07's Act V "built" two sections and produced no space, table or page.
293	      // So flag it: `turn.interrupted` lets the caller re-send once the pod is back (see run.mjs).
294	      if (this.sessionGone) {
295	        if (sawWork) return { ...this.turn(startSeq, Date.now() - t0), interrupted: true };
296	        throw new Error(`session ${this.sessionId} disappeared before doing any work (pod restart mid-init?)`);
297	      }
298	
299	      // Drain asks (consent cards, forms) — an unanswered ask stalls the turn forever.
300	      for (const ask of await this.openAsks().catch(() => [])) {
301	        if (this.asks.some((a) => a.id === ask.id)) continue;
302	        const answer = this.onAsk ? this.onAsk(ask.descriptor, ask) : undefined;
303	        this.asks.push({ id: ask.id, descriptor: ask.descriptor, answered: answer });
304	        if (answer !== undefined) {
305	          await this.answerAsk(ask.id, answer).catch(() => {});
306	          lastChange = Date.now();
307	        }
308	      }
309	
310	      const sessions = await this.pod.req('GET', '/api/sessions').catch(() => ({ sessions: [] }));
311	      const me = (sessions.sessions ?? []).find((s) => s.sessionId === this.sessionId);
312	      const idle = me?.status === 'idle';
313	      if (me?.status === 'error') {
314	        await this.pullEvents();
315	        throw new Error(`session entered error state: ${JSON.stringify(me)}`);
316	      }
317	      // Session no longer listed but we saw work → treat as completed (same eviction case).
318	      if (sawWork && !me && this.events.length > startSeq) {
319	        return this.turn(startSeq, Date.now() - t0);
320	      }
321	
322	      if (sawWork && idle && Date.now() - lastChange >= quietMs) {
323	        if (quietSince === null) quietSince = Date.now();
324	        await this.pullEvents(); // final drain
325	        return this.turn(startSeq, Date.now() - t0);
326	      }
327	      await sleep(pollMs);
328	    }
329	    await this.pullEvents();
330	    const open = await this.openAsks();
331	    throw Object.assign(
332	      new Error(
333	        `turn timed out after ${timeoutMs}ms` +
334	          (open.length ? ` with ${open.length} unanswered ask(s): ${JSON.stringify(open)}` : ''),
335	      ),
336	      { turn: this.turn(startSeq, Date.now() - t0), openAsks: open },
337	    );
338	  }
339	
340	  /** A view over just the events of one turn, with the derived facts a scenario asserts on. */
341	  turn(startSeq = 0, durationMs = 0) {
342	    const evs = this.events.slice(startSeq);
343	    return {
344	      durationMs,
345	      events: evs,
346	      text: textOf(evs),
347	      /** ONLY the turn's final display — the reply the user actually reads. `text` concatenates every
348	       *  display in the slice, which on a RESUMED session can still include replayed history, so a
349	       *  check about "what it answered" must read this, never `text`. */
350	      lastText: lastTextOf(evs),
351	      yields: evs.filter((e) => e.type === 'yield').map((e) => ({ kind: e.kind, args: e.args })),
352	      delegates: evs
353	        .filter((e) => e.type === 'yield' && e.kind === 'delegate')
354	        .map((e) => delegateRef(e.args)),
355	      errors: evs
356	        .filter((e) => e.type === 'eval_error' || e.type === 'typecheck_error')
357	        .map((e) => ({ type: e.type, message: e.message, statement: e.statement })),
358	      tokens: evs.reduce(
359	        (acc, e) =>
360	          e.type === 'llm_response'
361	            ? { in: acc.in + (e.inputTokens ?? 0), out: acc.out + (e.outputTokens ?? 0) }
362	            : acc,
363	        { in: 0, out: 0 },
364	      ),
365	      llmCalls: evs.filter((e) => e.type === 'llm_response').length,
366	      nodes: evs
367	        .filter((e) => e.type === 'node_end')
368	        .map((e) => ({ id: e.nodeId, status: e.status, ms: e.durationMs, error: e.error })),
369	    };
370	  }
371	
372	  /** Did the agent call this yield kind anywhere in the session? (e.g. 'installSpace') */
373	  didYield = (kind) => this.events.some((e) => e.type === 'yield' && e.kind === kind);
374	  /** Did it delegate to this `space/agent` (or just this space)? */
375	  didDelegate = (ref) =>
376	    this.events.some(
377	      (e) => e.type === 'yield' && e.kind === 'delegate' && delegateRef(e.args).startsWith(ref),
378	    );
379	  /** All consent cards raised this session. */
380	  consentCards = () => this.asks.filter((a) => a.descriptor?.type === 'ConsentCard');
381	
382	  /** Full session totals — for the performance table in the scenario report. */
383	  stats() {
384	    const t = this.turn(0, 0);
385	    return {
386	      events: this.events.length,
387	      llmCalls: t.llmCalls,
388	      tokens: t.tokens,
389	      errors: t.errors.length,
390	      delegates: t.delegates,
391	      yieldKinds: [...new Set(t.yields.map((y) => y.kind))],
392	    };
393	  }
394	}
395	
396	/** Human-readable delegate target from the yield args (`{space, agent, action}` or positional). */
397	function delegateRef(args) {
398	  if (Array.isArray(args)) return args.slice(0, 3).filter(Boolean).join('/');
399	  if (args && typeof args === 'object') {
400	    const { space, agent, action } = args;
401	    return [space, agent, action].filter(Boolean).join('/');
402	  }
403	  return String(args);
404	}
405	
406	/** The prose THING showed the user: display() descriptors + the final assistant text. */
407	export function textOf(events) {
408	  const out = [];
409	  for (const e of events) {
410	    if (e.type === 'display') {
411	      const d = e.descriptor;
412	      const s =
413	        typeof d === 'string'
414	          ? d
415	          : (d?.props?.text ?? d?.props?.children ?? d?.props?.content ?? JSON.stringify(d));
416	      out.push(typeof s === 'string' ? s : JSON.stringify(s));
417	    }
418	  }
419	  return out.join('\n');
420	}
421	
422	/** The LAST thing THING displayed — its final reply for this turn (see `turn().lastText`). */
423	export function lastTextOf(events) {
424	  for (let i = events.length - 1; i >= 0; i--) {
425	    const e = events[i];
426	    if (e.type !== 'display') continue;
427	    const d = e.descriptor;
428	    const s =
429	      typeof d === 'string'
430	        ? d
431	        : (d?.props?.text ?? d?.props?.children ?? d?.props?.content ?? JSON.stringify(d));
432	    const out = typeof s === 'string' ? s : JSON.stringify(s);
433	    if (out && out.trim()) return out;
434	  }
435	  return '';
436	}
437	
438	/** Approve every consent card; leave other asks for the scenario. */
439	export const approveAllConsent = (descriptor) =>
440	  descriptor?.type === 'ConsentCard' ? true : undefined;
441	/** Deny every consent card (for the denial branch of the consent scenario). */
442	export const denyAllConsent = (descriptor) =>
443	  descriptor?.type === 'ConsentCard' ? false : undefined;
