226	  // ── uploads (chat attachments) ──────────────────────────────────────────
227	  /**
228	   * The mediaType decides the pod's ROUTE, not just a label: `image/*` goes to system-vision,
229	   * `audio/*` is transcribed at ingest, everything else goes to system-files. So a `.mp3` sent as
230	   * `application/octet-stream` is never transcribed, and a scenario asserting "a spoken-only fact
231	   * reached a row" fails for a reason that has nothing to do with the product. Every fixture type the
232	   * scenarios actually upload must be in this table.
233	   */
234	  static MEDIA_TYPES = {
235	    '.md': 'text/markdown',
236	    '.txt': 'text/plain',
237	    '.csv': 'text/csv',
238	    '.json': 'application/json',
239	    '.pdf': 'application/pdf',
240	    '.jpg': 'image/jpeg',
241	    '.jpeg': 'image/jpeg',
242	    '.png': 'image/png',
243	    '.webp': 'image/webp',
244	    '.gif': 'image/gif',
245	    '.mp3': 'audio/mpeg',
246	    '.m4a': 'audio/mp4',
247	    '.wav': 'audio/wav',
248	    '.ogg': 'audio/ogg',
249	    '.webm': 'audio/webm',
250	    '.xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
251	    '.xls': 'application/vnd.ms-excel',
252	    '.docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
253	  };
254	
255	  /**
256	   * Upload a local file as a chat attachment (the UI's "load a file" action).
257	   * `POST /api/uploads` takes base64 + mediaType and returns an AttachmentRef
258	   * (`{id, kind, mediaType, filename?, url}`) that a message then references by id.
259	   * Pair with `ThingSession.sendWithAttachments()` (WS path — HTTP /message drops attachments).
260	   *
261	   * Throws on an unknown extension rather than silently sending `application/octet-stream` — a
262	   * misrouted attachment turns a real product failure into a green test (see MEDIA_TYPES).
263	   */
264	  async upload(filePath, { mediaType, filename } = {}) {
265	    const { readFileSync } = await import('node:fs');
266	    const { basename, extname } = await import('node:path');
267	    const bytes = readFileSync(filePath);
268	    const ext = extname(filePath).toLowerCase();
269	    const mt = mediaType ?? Pod.MEDIA_TYPES[ext];
270	    if (!mt) {
271	      throw new Error(
272	        `upload(${basename(filePath)}): no mediaType known for "${ext}" — pass { mediaType } explicitly ` +
273	          `or add it to Pod.MEDIA_TYPES. Guessing octet-stream would misroute it (no vision, no transcription).`,
274	      );
275	    }
276	    const ref = await this.req('POST', '/api/uploads', {
277	      filename: filename ?? basename(filePath),
278	      mediaType: mt,
279	      data: bytes.toString('base64'),
280	    });
281	    return ref;
282	  }
283	
284	  // ── accounting ──────────────────────────────────────────────────────────
285	  /** Pod-global token/cost ledger — includes the DELEGATE tree, not just top-level turns. */
286	  sessionLedger = () => this.req('GET', '/api/session-ledger');
287	  /** The gateway's spend-window report, as the pod sees it. */
288	  budget = () => this.req('GET', '/api/budget');
289	
290	  // ── env / lifecycle ─────────────────────────────────────────────────────
