        t=re.search(r't="([^"]+)"',attrs)
        t=t.group(1) if t else None
        v=re.search(r'<t[^>]*>(.*?)</t>',inner) or re.search(r'<v>(.*?)</v>',inner)
        val=v.group(1) if v else ''
        rows.setdefault(rownum(ref),{})[col(ref)]=val
    for r in sorted(rows)[:20]:
        print(r, {k:rows[r][k] for k in sorted(rows[r])})
